from flask import Flask, request, jsonify, abort

app = Flask(__name__)



VAULT_ACCESS_KEY = "AKIA-VAULT-ACCESS-XYZ"
VAULT_SECRET_KEY = "sunshine_is_not_enough_123"


ENCRYPTED_STATE_B64 = ""
CIPHER_KEY_HEX = "73756e7368696e655f6b65795f333262797465735f65786163746c795f212121"
CIPHER_IV_HEX = "696e69745f766563746f725f31366221"

@app.route('/api/v1/vault/state', methods=['GET'])
def state_dump():
    access_key = request.headers.get('X-Vault-Access-Key')
    secret_key = request.headers.get('X-Vault-Secret-Key')

    if not access_key or not secret_key:
        abort(403, description="Access forbidden: Missing Vault authentication headers (X-Vault-Access-Key, X-Vault-Secret-Key)")

    if access_key != VAULT_ACCESS_KEY or secret_key != VAULT_SECRET_KEY:
        abort(403, description="Access forbidden: Invalid authentication credentials")

    try:
        return jsonify({
            "message": "Authentication successful. Terraform state is encrypted.",
            "encryption_algorithm": "AES-256-CBC",
            "key_hex": CIPHER_KEY_HEX,
            "iv_hex": CIPHER_IV_HEX,
            "ciphertext_base64": ENCRYPTED_STATE_B64
        })
    except Exception as e:
        abort(500, description=str(e))

if __name__ == '__main__':

    app.run(host='0.0.0.0', port=5000)
